                        _home_m = _home_ml_pub.get("money",0)
                        _away_t = _away_ml_pub.get("tickets",0)
                        _away_m = _away_ml_pub.get("money",0)
                        st.caption(f"{_g.get('home','Home')}: 🎟️ {_home_t}% | 💰 {_home_m}%")
                        st.caption(f"{_g.get('away','Away')}: 🎟️ {_away_t}% | 💰 {_away_m}%")
